-// TODO: implement client
+// Notes SPA client
+// Requirements:
+// - Use same-origin API base: /api/notes
+// - GET must NOT send API key header
+// - POST/PUT/DELETE must send Content-Type: application/json and X-API-Key
+
+const API_BASE = '/api/notes';
+
+let apiKey = '';
+let activeNoteId = null;
+
+function $(id) {
+  return document.getElementById(id);
+}
+
+function getKey() {
+  // In the harness, fetch exists; this runs in a "browser-like" environment.
+  // Load key once; keep it trimmed.
+  if (apiKey) return Promise.resolve(apiKey);
+  return fetch('/config/api.key')
+    .then((r) => r.text())
+    .then((t) => {
+      apiKey = (t || '').trim();
+      return apiKey;
+    });
+}
+
+function headersWithKey() {
+  return getKey().then((k) => ({
+    'Content-Type': 'application/json',
+    'X-API-Key': k
+  }));
+}
+
+function clearForm() {
+  const title = $('note-title');
+  const content = $('note-content');
+  if (title) title.value = '';
+  if (content) content.value = '';
+  activeNoteId = null;
+}
+
+function setFormFromNote(note) {
+  const title = $('note-title');
+  const content = $('note-content');
+  if (title) title.value = note && note.title != null ? String(note.title) : '';
+  if (content) content.value = note && note.content != null ? String(note.content) : '';
+}
+
+function renderNotes(notes) {
+  const list = $('notes-list');
+  if (!list) return;
+  list.innerHTML = '';
+
+  (notes || []).forEach((note) => {
+    const row = document.createElement('div');
+    row.className = 'note-row';
+    row.dataset.noteId = String(note.id);
+
+    const title = document.createElement('span');
+    title.className = 'note-title';
+    title.textContent = note.title == null ? '' : String(note.title);
+
+    const content = document.createElement('span');
+    content.className = 'note-content';
+    content.textContent = note.content == null ? '' : String(note.content);
+
+    const editBtn = document.createElement('button');
+    editBtn.type = 'button';
+    editBtn.className = 'edit-btn';
+    editBtn.textContent = 'Edit';
+    editBtn.dataset.noteId = String(note.id);
+
+    const deleteBtn = document.createElement('button');
+    deleteBtn.type = 'button';
+    deleteBtn.className = 'delete-btn';
+    deleteBtn.textContent = 'Delete';
+    deleteBtn.dataset.noteId = String(note.id);
+
+    row.appendChild(title);
+    row.appendChild(content);
+    row.appendChild(editBtn);
+    row.appendChild(deleteBtn);
+    list.appendChild(row);
+  });
+}
+
+function loadNotes() {
+  // GET should not send API key.
+  return fetch(API_BASE)
+    .then((r) => r.json())
+    .then((data) => {
+      // API may return array directly or {notes:[...]}
+      const notes = Array.isArray(data) ? data : (data && data.notes) ? data.notes : [];
+      renderNotes(notes);
+      return notes;
+    });
+}
+
+function createNote(payload) {
+  return headersWithKey().then((headers) =>
+    fetch(API_BASE, {
+      method: 'POST',
+      headers,
+      body: JSON.stringify(payload)
+    })
+  );
+}
+
+function updateNote(id, payload) {
+  return headersWithKey().then((headers) =>
+    fetch(`${API_BASE}/${encodeURIComponent(String(id))}`, {
+      method: 'PUT',
+      headers,
+      body: JSON.stringify(payload)
+    })
+  );
+}
+
+function deleteNote(id) {
+  return headersWithKey().then((headers) =>
+    fetch(`${API_BASE}/${encodeURIComponent(String(id))}`, {
+      method: 'DELETE',
+      headers
+    })
+  );
+}
+
+function noteFromRow(row) {
+  const id = row && row.dataset ? row.dataset.noteId : null;
+  const titleEl = row ? row.querySelector('.note-title') : null;
+  const contentEl = row ? row.querySelector('.note-content') : null;
+  return {
+    id: id,
+    title: titleEl ? titleEl.textContent : '',
+    content: contentEl ? contentEl.textContent : ''
+  };
+}
+
+function wireEvents() {
+  const form = $('note-form');
+  const list = $('notes-list');
+
+  if (form) {
+    form.addEventListener('submit', (e) => {
+      e.preventDefault();
+      const title = ($('note-title') && $('note-title').value != null) ? $('note-title').value : '';
+      const content = ($('note-content') && $('note-content').value != null) ? $('note-content').value : '';
+
+      const payload = {
+        title: String(title).trim(),
+        content: String(content).trim()
+      };
+
+      const op = activeNoteId ? updateNote(activeNoteId, payload) : createNote(payload);
+      op.then(() => {
+        clearForm();
+        return loadNotes();
+      });
+    });
+  }
+
+  if (list) {
+    // Event delegation to satisfy mock DOM quirks.
+    list.addEventListener('click', (e) => {
+      const t = e && e.target ? e.target : null;
+      if (!t) return;
+
+      if (t.classList && t.classList.contains('edit-btn')) {
+        const id = t.dataset ? t.dataset.noteId : null;
+        activeNoteId = id;
+        const row = t.closest ? t.closest('[data-note-id]') : null;
+        const note = row ? noteFromRow(row) : { title: '', content: '' };
+        setFormFromNote(note);
+        return;
+      }
+
+      if (t.classList && t.classList.contains('delete-btn')) {
+        const id = t.dataset ? t.dataset.noteId : null;
+        deleteNote(id).then(() => loadNotes());
+      }
+    });
+  }
+}
+
+// Boot
+wireEvents();
+loadNotes();
*** End Patch
